Object.assign(LORE_EXTRA_101, {"ep056-01":{"originStory":"언덕(虍)과 빈 그릇이 합쳐져, 속이 텅 비어 아무것도 없는 상태를 뜻한다. ‘비다, 헛되다’를 가리킨다.","vocabulary":[{"word":"虛空 (허공)","meaning":"텅 빈 공간"},{"word":"虛無 (허무)","meaning":"아무것도 없이 텅 빔"}],"radical":"虍","strokeCount":12},"ep056-02":{"originStory":"흙(土)을 높이 돋워 세운 건물에서, 사람들이 모이는 ‘집, 큰 마루’를 뜻한다.","vocabulary":[{"word":"講堂 (강당)","meaning":"여럿이 모여 강의를 듣는 큰 방"},{"word":"食堂 (식당)","meaning":"밥을 먹는 곳"}],"radical":"土","strokeCount":11},"ep056-03":{"originStory":"어린 새가 깃(羽)을 퍼덕이며 나는 법을 거듭 연습하는 데서, ‘익히다, 배우다’를 뜻한다.","vocabulary":[{"word":"練習 (연습)","meaning":"되풀이하여 익힘"},{"word":"學習 (학습)","meaning":"배워서 익힘"}],"radical":"羽","strokeCount":11},"ep056-04":{"originStory":"귀(耳)를 기울여 소리를 받아들이는 데서, ‘듣다’를 뜻한다.","vocabulary":[{"word":"聽衆 (청중)","meaning":"강연이나 음악을 듣는 사람들"},{"word":"傾聽 (경청)","meaning":"귀를 기울여 들음"}],"radical":"耳","strokeCount":22},"ep057-01":{"originStory":"신(示)이 내리는 뜻밖의 어그러짐에서, ‘재앙, 불행’을 뜻한다.","vocabulary":[{"word":"災禍 (재화)","meaning":"재앙과 화"},{"word":"禍根 (화근)","meaning":"재앙의 뿌리"}],"radical":"示","strokeCount":14},"ep057-02":{"originStory":"자리(囗) 위에 누운 사람(大)이 무언가에 기대는 모습에서, ‘말미암다, 까닭, 인하다’를 뜻한다.","vocabulary":[{"word":"原因 (원인)","meaning":"일이 일어난 까닭"},{"word":"因緣 (인연)","meaning":"서로 맺어진 관계"}],"radical":"囗","strokeCount":6},"ep057-03":{"originStory":"마음(心)이 비뚤어진(亞) 데서, ‘악하다, 나쁘다’를 뜻한다. ‘미워하다’의 뜻일 땐 ‘오’로 읽는다.","vocabulary":[{"word":"惡人 (악인)","meaning":"나쁜 사람"},{"word":"善惡 (선악)","meaning":"착함과 악함"}],"radical":"心","strokeCount":12},"ep057-04":{"originStory":"벼(禾)를 차곡차곡 쌓아 모으는 데서, ‘쌓다, 모으다’를 뜻한다.","vocabulary":[{"word":"積金 (적금)","meaning":"돈을 모아 쌓음"},{"word":"累積 (누적)","meaning":"포개어 쌓임"}],"radical":"禾","strokeCount":16},"ep058-01":{"originStory":"신(示)이 내려 가득(畐) 채워 주는 데서, ‘복, 행복’을 뜻한다.","vocabulary":[{"word":"幸福 (행복)","meaning":"흐뭇하고 즐거운 상태"},{"word":"福音 (복음)","meaning":"기쁜 소식"}],"radical":"示","strokeCount":14},"ep058-02":{"originStory":"실(糸)이 옷단을 따라 이어지듯 서로 맺어지는 데서, ‘인연, 가장자리’를 뜻한다.","vocabulary":[{"word":"因緣 (인연)","meaning":"서로 맺어진 관계"},{"word":"緣分 (연분)","meaning":"서로 맺어지는 인연"}],"radical":"糸","strokeCount":15},"ep058-03":{"originStory":"양(羊)처럼 순하고 곱고 바른 것에서, ‘착하다, 좋다, 잘하다’를 뜻한다.","vocabulary":[{"word":"善良 (선량)","meaning":"착하고 어짊"},{"word":"最善 (최선)","meaning":"가장 좋고 온 힘을 다함"}],"radical":"口","strokeCount":12},"ep058-04":{"originStory":"사슴(鹿) 가죽을 선물로 들고 마음(心)을 다해 축하하러 가는 데서, ‘경사, 축하하다’를 뜻한다.","vocabulary":[{"word":"慶事 (경사)","meaning":"축하할 만한 기쁜 일"},{"word":"慶祝 (경축)","meaning":"경사를 축하함"}],"radical":"心","strokeCount":15},"ep059-01":{"originStory":"손가락을 펴서 길이를 재는 모양에서, 길이의 단위인 ‘자’를 뜻한다.","vocabulary":[{"word":"尺度 (척도)","meaning":"재는 기준이나 자"},{"word":"縮尺 (축척)","meaning":"실제를 줄여 나타낸 비율"}],"radical":"尸","strokeCount":4},"ep059-02":{"originStory":"임금(辟)이 지니던 둥글고 가운데 구멍 뚫린 옥(玉)에서, ‘둥근 옥, 구슬’을 뜻한다.","vocabulary":[{"word":"完璧 (완벽)","meaning":"흠 없이 완전함"},{"word":"璧玉 (벽옥)","meaning":"둥근 옥"}],"radical":"玉","strokeCount":18},"ep059-03":{"originStory":"새가 양 날개를 펴고 서로 등진 모양에서, ‘아니다, 그르다’를 뜻한다.","vocabulary":[{"word":"非難 (비난)","meaning":"남의 잘못을 나무람"},{"word":"是非 (시비)","meaning":"옳고 그름"}],"radical":"非","strokeCount":8},"ep059-04":{"originStory":"집(宀) 안에 옥(玉)과 재물(貝)을 잘 간직한 데서, ‘보배, 보물’을 뜻한다.","vocabulary":[{"word":"寶物 (보물)","meaning":"보배로운 물건"},{"word":"國寶 (국보)","meaning":"나라의 보배"}],"radical":"宀","strokeCount":20},"ep060-01":{"originStory":"손목에서 맥을 짚는 한 마디 자리를 가리켜, ‘마디’와 아주 짧은 길이를 뜻한다.","vocabulary":[{"word":"寸數 (촌수)","meaning":"친족 사이의 멀고 가까운 정도"},{"word":"寸劇 (촌극)","meaning":"아주 짧은 연극"}],"radical":"寸","strokeCount":3},"ep060-02":{"originStory":"언덕(阝)에 해가 가려 그늘진 데서, ‘그늘, 음(陰)’을 뜻한다.","vocabulary":[{"word":"陰地 (음지)","meaning":"볕이 들지 않는 곳"},{"word":"光陰 (광음)","meaning":"햇빛과 그늘, 곧 시간"}],"radical":"阜","strokeCount":11},"ep060-03":{"originStory":"해(日)처럼 바르고(正) 곧은 데서, ‘옳다, 이, 이것’을 뜻한다.","vocabulary":[{"word":"是非 (시비)","meaning":"옳고 그름"},{"word":"是正 (시정)","meaning":"잘못을 바로잡음"}],"radical":"日","strokeCount":9},"ep060-04":{"originStory":"두 사람이 마주 서서 힘껏 겨루는 모습에서, ‘다투다, 겨루다’를 뜻한다.","vocabulary":[{"word":"競爭 (경쟁)","meaning":"서로 겨루어 다툼"},{"word":"競技 (경기)","meaning":"솜씨를 겨루는 운동"}],"radical":"立","strokeCount":20},"ep061-01":{"originStory":"재물(貝)을 버금가게(次) 갖춘 데서, ‘재물, 밑천, 도움’을 뜻한다.","vocabulary":[{"word":"資金 (자금)","meaning":"사업이나 일에 드는 돈"},{"word":"資料 (자료)","meaning":"바탕이 되는 거리"}],"radical":"貝","strokeCount":13},"ep061-02":{"originStory":"손에 막대를 든 모양에서, 집안을 이끄는 ‘아버지’를 뜻한다.","vocabulary":[{"word":"父母 (부모)","meaning":"아버지와 어머니"},{"word":"祖父 (조부)","meaning":"할아버지"}],"radical":"父","strokeCount":4},"ep061-03":{"originStory":"손에 도구를 들고 맡은 일을 하는 데서, ‘일, 섬기다’를 뜻한다.","vocabulary":[{"word":"事件 (사건)","meaning":"벌어진 일"},{"word":"從事 (종사)","meaning":"어떤 일에 매달림"}],"radical":"亅","strokeCount":8},"ep061-04":{"originStory":"손에 권위를 상징하는 막대를 들고 입(口)으로 명령을 내리는 데서, ‘임금, 그대’를 뜻한다.","vocabulary":[{"word":"君主 (군주)","meaning":"나라를 다스리는 임금"},{"word":"君子 (군자)","meaning":"덕이 높은 사람"}],"radical":"口","strokeCount":7},"ep062-01":{"originStory":"입(口)에서 말이 나가는 모양을 본떠, ‘말하다, 가로되’를 뜻한다.","vocabulary":[{"word":"曰可曰否 (왈가왈부)","meaning":"옳다 그르다 말함"}],"radical":"曰","strokeCount":4},"ep062-02":{"originStory":"엄하게 호령하는 입(口)과 위세에서, ‘엄하다, 무섭다’를 뜻한다.","vocabulary":[{"word":"嚴格 (엄격)","meaning":"매우 엄하고 철저함"},{"word":"威嚴 (위엄)","meaning":"엄숙하고 무게 있는 태도"}],"radical":"口","strokeCount":20},"ep062-03":{"originStory":"여러 손이 함께 힘을 모아 들어 올리고 주고받는 데서, ‘더불다, 주다’를 뜻한다.","vocabulary":[{"word":"與否 (여부)","meaning":"그러함과 그렇지 않음"},{"word":"參與 (참여)","meaning":"함께 끼어듦"}],"radical":"臼","strokeCount":14},"ep062-04":{"originStory":"삼가는 마음으로 몸가짐을 다잡는(苟) 데서, ‘공경하다, 삼가다’를 뜻한다.","vocabulary":[{"word":"尊敬 (존경)","meaning":"높이 받들어 공경함"},{"word":"敬禮 (경례)","meaning":"공경의 뜻으로 하는 인사"}],"radical":"攴","strokeCount":13},"ep063-01":{"originStory":"자식(子)이 늙은 어버이(老)를 받들어 모시는 모습에서, ‘효도’를 뜻한다.","vocabulary":[{"word":"孝道 (효도)","meaning":"부모를 잘 섬김"},{"word":"孝誠 (효성)","meaning":"부모를 섬기는 정성"}],"radical":"子","strokeCount":7},"ep063-02":{"originStory":"밭(田)을 마주 보아 값이 맞먹는 데서, ‘마땅하다, 당하다, 맡다’를 뜻한다.","vocabulary":[{"word":"當然 (당연)","meaning":"마땅히 그러함"},{"word":"擔當 (담당)","meaning":"일을 맡음"}],"radical":"田","strokeCount":13},"ep063-03":{"originStory":"세워 둔(立) 물을 끝까지 퍼내 바닥나게 하는 데서, ‘다하다, 없어지다’를 뜻한다.","vocabulary":[{"word":"竭力 (갈력)","meaning":"있는 힘을 다함"},{"word":"枯竭 (고갈)","meaning":"말라서 다 없어짐"}],"radical":"立","strokeCount":14},"ep063-04":{"originStory":"팔에 힘을 주어 일하는 팔뚝의 모양을 본떠, ‘힘’을 뜻한다.","vocabulary":[{"word":"努力 (노력)","meaning":"애써 힘씀"},{"word":"能力 (능력)","meaning":"일을 해내는 힘"}],"radical":"力","strokeCount":2},"ep064-01":{"originStory":"마음(心)이 한가운데(中)에 곧게 자리해 치우치지 않는 데서, ‘충성, 정성’을 뜻한다.","vocabulary":[{"word":"忠誠 (충성)","meaning":"마음을 다해 섬김"},{"word":"忠告 (충고)","meaning":"진심으로 잘못을 일러 줌"}],"radical":"心","strokeCount":8},"ep064-02":{"originStory":"재물(貝)을 칼(刂)로 나누듯 법도를 정한 데서, ‘법칙, 곧’을 뜻한다. ‘곧’의 뜻일 땐 ‘즉’으로 읽는다.","vocabulary":[{"word":"規則 (규칙)","meaning":"정해 놓은 법"},{"word":"原則 (원칙)","meaning":"기본이 되는 법칙"}],"radical":"刀","strokeCount":9},"ep064-03":{"originStory":"그릇(皿)의 음식을 손으로 깨끗이 비우는 데서, ‘다하다, 끝내다’를 뜻한다.","vocabulary":[{"word":"盡力 (진력)","meaning":"있는 힘을 다함"},{"word":"賣盡 (매진)","meaning":"다 팔려 동남"}],"radical":"皿","strokeCount":14},"ep064-04":{"originStory":"입(口)으로 명령(令)을 내려 시키는 데서, ‘목숨, 명령’을 뜻한다.","vocabulary":[{"word":"生命 (생명)","meaning":"목숨"},{"word":"命令 (명령)","meaning":"시키는 분부"}],"radical":"口","strokeCount":8},"ep065-01":{"originStory":"눈을 크게 떠 높은 곳에서 아래를 굽어보는 데서, ‘임하다, 다다르다’를 뜻한다.","vocabulary":[{"word":"臨時 (임시)","meaning":"잠시 동안"},{"word":"君臨 (군림)","meaning":"임금으로서 다스림"}],"radical":"臣","strokeCount":17},"ep065-02":{"originStory":"물(氵)이 한참 들어가야 바닥에 닿는 데서, ‘깊다’를 뜻한다.","vocabulary":[{"word":"深海 (심해)","meaning":"깊은 바다"},{"word":"深刻 (심각)","meaning":"정도가 매우 깊고 중함"}],"radical":"氵","strokeCount":11},"ep065-03":{"originStory":"주검(尸) 아래 발걸음을 신에 받쳐 걷는 데서, ‘신, 밟다, 행하다’를 뜻한다.","vocabulary":[{"word":"履行 (이행)","meaning":"약속을 실제로 행함"},{"word":"履歷 (이력)","meaning":"지나온 일들의 자취"}],"radical":"尸","strokeCount":15},"ep065-04":{"originStory":"풀(艹)과 물이 얇게 덮인 데서, ‘엷다, 얇다, 박하다’를 뜻한다.","vocabulary":[{"word":"薄氷 (박빙)","meaning":"살얼음, 아주 근소한 차이"},{"word":"稀薄 (희박)","meaning":"묽고 엷음"}],"radical":"艹","strokeCount":17},"ep066-01":{"originStory":"이른 새벽 아직 달(夕)이 남아 있을 때 일어나는 데서, ‘이르다, 이른 아침’을 뜻한다.","vocabulary":[{"word":"夙興 (숙흥)","meaning":"아침 일찍 일어남"},{"word":"夙夜 (숙야)","meaning":"이른 아침과 늦은 밤"}],"radical":"夕","strokeCount":6},"ep066-02":{"originStory":"여러 손이 함께 힘을 모아 들어 일으키는 데서, ‘일어나다, 흥하다’를 뜻한다.","vocabulary":[{"word":"興奮 (흥분)","meaning":"마음이 들떠 일어남"},{"word":"復興 (부흥)","meaning":"다시 일어나 번성함"}],"radical":"臼","strokeCount":16},"ep066-03":{"originStory":"물(氵)을 그릇에 담아 데워 따뜻하게 하는 데서, ‘따뜻하다’를 뜻한다.","vocabulary":[{"word":"溫度 (온도)","meaning":"덥고 찬 정도"},{"word":"溫暖 (온난)","meaning":"날씨가 따뜻함"}],"radical":"氵","strokeCount":13},"ep066-04":{"originStory":"얼음(冫)처럼 푸르고(靑) 차가운 데서, ‘서늘하다’를 뜻한다.","vocabulary":[{"word":"凊涼 (청량)","meaning":"서늘하고 시원함"}],"radical":"冫","strokeCount":10},"ep067-01":{"originStory":"사람(亻)이 본보기와 닮아 비슷한 데서, ‘같다, 닮다’를 뜻한다.","vocabulary":[{"word":"類似 (유사)","meaning":"서로 비슷함"},{"word":"似而非 (사이비)","meaning":"겉은 같으나 속은 다름"}],"radical":"亻","strokeCount":7},"ep067-02":{"originStory":"풀(艹)의 한 갈래로, 향기가 그윽한 ‘난초’를 뜻한다.","vocabulary":[{"word":"蘭草 (난초)","meaning":"향기로운 풀의 하나"},{"word":"金蘭 (금란)","meaning":"쇠처럼 굳고 난초처럼 향기로운 우정"}],"radical":"艹","strokeCount":21},"ep067-03":{"originStory":"도끼(斤)로 갈라 나누는 데서, ‘이, 이것’이라는 가리킴말로 쓰인다.","vocabulary":[{"word":"斯界 (사계)","meaning":"이 분야"}],"radical":"斤","strokeCount":12},"ep067-04":{"originStory":"향기(香)가 멀리 퍼져 나가는 데서, ‘꽃답다, 향기가 멀리 가다’를 뜻한다.","vocabulary":[{"word":"馨香 (형향)","meaning":"꽃다운 향기"}],"radical":"香","strokeCount":20},"ep068-01":{"originStory":"여자(女)가 입(口)으로 시키는 대로 좇아 따르는 데서, ‘같다, 만일’을 뜻한다.","vocabulary":[{"word":"如前 (여전)","meaning":"전과 같음"},{"word":"缺如 (결여)","meaning":"마땅히 있어야 할 것이 빠짐"}],"radical":"女","strokeCount":6},"ep068-02":{"originStory":"나무(木) 가운데 사철 푸른 ‘소나무’를 뜻한다.","vocabulary":[{"word":"松林 (송림)","meaning":"소나무 숲"},{"word":"靑松 (청송)","meaning":"푸른 소나무"}],"radical":"木","strokeCount":8},"ep068-03":{"originStory":"발이 땅을 떠나 나아가는 모양에서, ‘가다’를 뜻하며, ‘~의, 이것’을 가리키는 말로도 쓰인다.","vocabulary":[{"word":"之東之西 (지동지서)","meaning":"갈팡질팡 일정한 방향이 없음"}],"radical":"丿","strokeCount":4},"ep068-04":{"originStory":"그릇(皿)에 음식이 넘치도록 가득 담긴 데서, ‘성하다, 가득하다’를 뜻한다.","vocabulary":[{"word":"盛大 (성대)","meaning":"아주 크고 풍성함"},{"word":"茂盛 (무성)","meaning":"풀과 나무가 우거짐"}],"radical":"皿","strokeCount":12},"ep069-01":{"originStory":"양쪽 기슭 사이로 물이 흐르는 모양을 본떠, ‘내, 시내’를 뜻한다.","vocabulary":[{"word":"河川 (하천)","meaning":"강과 시내"},{"word":"山川 (산천)","meaning":"산과 내, 곧 자연"}],"radical":"川","strokeCount":3},"ep069-02":{"originStory":"물(氵)이 막힘없이 흘러 내려가는 데서, ‘흐르다’를 뜻한다.","vocabulary":[{"word":"流水 (유수)","meaning":"흐르는 물"},{"word":"交流 (교류)","meaning":"서로 오가며 주고받음"}],"radical":"氵","strokeCount":10},"ep069-03":{"originStory":"꽃받침이 아직 열매를 맺지 못한 모양에서, ‘아니다, 못하다’라는 부정의 뜻이 되었다.","vocabulary":[{"word":"不可 (불가)","meaning":"할 수 없거나 옳지 않음"},{"word":"不足 (부족)","meaning":"넉넉하지 못함"}],"radical":"一","strokeCount":4},"ep069-04":{"originStory":"코(自)로 숨을 쉬어 마음(心)을 가라앉히는 데서, ‘쉬다, 숨쉬다’를 뜻한다.","vocabulary":[{"word":"休息 (휴식)","meaning":"잠시 쉼"},{"word":"歎息 (탄식)","meaning":"한숨 쉬며 한탄함"}],"radical":"心","strokeCount":10},"ep070-01":{"originStory":"물(氵)이 깊이 고여 빙빙 도는 못의 모양에서, ‘못, 깊다’를 뜻한다.","vocabulary":[{"word":"深淵 (심연)","meaning":"깊은 못, 헤어나기 어려운 곳"}],"radical":"氵","strokeCount":12},"ep070-02":{"originStory":"물(氵)이 가라앉아 티 없이 맑아진 데서, ‘맑다, 맑게 하다’를 뜻한다.","vocabulary":[{"word":"澄淸 (징청)","meaning":"물 따위가 맑고 깨끗함"}],"radical":"氵","strokeCount":15},"ep070-03":{"originStory":"손(又)으로 귀(耳)를 잡아 가지는 데서, ‘가지다, 취하다’를 뜻한다.","vocabulary":[{"word":"取得 (취득)","meaning":"자기 것으로 얻음"},{"word":"取捨 (취사)","meaning":"쓸 것과 버릴 것을 가림"}],"radical":"又","strokeCount":8},"ep070-04":{"originStory":"해(日)와 빛이 가운데(央)로 비쳐 드는 데서, ‘비치다, 비추다’를 뜻한다.","vocabulary":[{"word":"映畵 (영화)","meaning":"스크린에 비추는 그림"},{"word":"反映 (반영)","meaning":"되비쳐 나타남"}],"radical":"日","strokeCount":9}});
Object.assign(EP_TRANS_101, {"ep056":{"title":"빈 집의 메아리","comboTranslation":"빈 집에서 익혀 들으니 소리가 잘 울려 퍼진다."},"ep057":{"title":"재앙은 악에서","comboTranslation":"재앙은 악한 일이 쌓이는 데서 말미암는다."},"ep058":{"title":"복은 선에서","comboTranslation":"복은 착한 일을 한 인연으로 경사가 따른다."},"ep059":{"title":"한 자의 옥구슬","comboTranslation":"한 자나 되는 큰 옥구슬도 참된 보배는 아니다."},"ep060":{"title":"짧은 시간을 다투다","comboTranslation":"한 치의 짧은 시간을 다투어 아껴야 한다."},"ep061":{"title":"아버지와 임금을 섬기다","comboTranslation":"아버지 섬기던 마음을 바탕으로 임금을 섬긴다."},"ep062":{"title":"엄함과 공경","comboTranslation":"그것은 엄숙함과 공경함을 말한다."},"ep063":{"title":"힘을 다하는 효","comboTranslation":"효도는 마땅히 온 힘을 다해야 한다."},"ep064":{"title":"목숨을 다하는 충","comboTranslation":"충성은 곧 목숨을 다해야 한다."},"ep065":{"title":"깊은 물 살얼음","comboTranslation":"깊은 물에 임하듯, 살얼음을 밟듯 조심한다."},"ep066":{"title":"효성의 도리","comboTranslation":"일찍 일어나 부모를 따뜻하고 서늘하게 해 드린다."},"ep067":{"title":"난초 같은 향기","comboTranslation":"난초처럼 그 향기가 멀리 퍼진다."},"ep068":{"title":"소나무 같은 무성함","comboTranslation":"소나무처럼 그 기상이 푸르고 무성하다."},"ep069":{"title":"쉬지 않는 냇물","comboTranslation":"냇물은 흘러 쉬지 않는다."},"ep070":{"title":"맑은 못의 비침","comboTranslation":"못은 맑아 그 모습을 잘 비춘다."}});

